1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	const HIGH_ENCHANTMENT_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	
10	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	type Item = {
18	  type: string;
19	  material?: string;
20	  enchantment?: number;
21	  cursed?: boolean;
22	};
23	type Step = { op: "quote"; items: Item[] };
24	type Scenario = { customer: unknown; steps: Step[] };
25	
26	const componentGroupPremium = (count: number): number =>
27	  count === COMPONENT_BLOCK_SIZE
28	    ? COMPONENT_BLOCK_PREMIUM
29	    : count * COMPONENT_BASE_PREMIUM;
30	
31	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
32	
33	const mainItemPremium = (item: Item): number => {
34	  const base = BASE_PREMIUM_BY_TYPE[item.type];
35	  const cursedRate = item.cursed ? CURSE_SURCHARGE_RATE : 0;
36	  const highEnchant = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
37	  const highEnchantRate = highEnchant ? HIGH_ENCHANTMENT_RATE : 0;
38	  const firstInsuranceRate = item.cursed && !highEnchant ? FIRST_INSURANCE_RATE : 0;
39	  return base * (1 + cursedRate + highEnchantRate + firstInsuranceRate);
40	};
41	
42	const countByType = (items: Item[]): Map<string, number> =>
43	  items.reduce(
44	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
45	    new Map<string, number>(),
46	  );
47	
48	const sumComponentPremiums = (components: Item[]): number =>
49	  [...countByType(components).values()]
50	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
51	
52	const sumItemPremiums = (items: Item[]): number => {
53	  const mains = items.filter(isMainItem);
54	  const components = items.filter((i) => !isMainItem(i));
55	  const mainsSum = mains.reduce((sum, item) => sum + mainItemPremium(item), 0);
56	  return mainsSum + sumComponentPremiums(components);
57	};
58	
59	const quotePremiumFor = (step: Step): { premium: number } => ({
60	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
61	});
62	
63	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
64	  results: scenario.steps.map(quotePremiumFor),
65	});
